"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
export default function RouteSnapshotCard(){const [open,setOpen]=useState(false);const reduced=useReducedMotion();return <article className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><div className="flex items-start justify-between"><div><p className="text-xs font-bold text-[#4a4a4f]">Delivery route</p><h2 className="text-xl font-black text-[#111]">North loop</h2></div><b className="rounded-xl bg-[#53e8d4] px-3 py-2 text-sm">68%</b></div><ol className="mt-5 flex items-center justify-between" aria-label="Route checkpoints">{["Plan","Review","Ship"].map((stop,index)=><li key={stop} className="flex flex-col items-center gap-1 text-xs font-bold text-[#4a4a4f]"><motion.span animate={{scale:index===1&&!reduced?1.18:1}} className={index===1?"grid h-7 w-7 place-items-center rounded-full bg-violet-300 text-[#111]":"grid h-7 w-7 place-items-center rounded-full bg-[#f4f5f6]"}>{index+1}</motion.span>{stop}</li>)}</ol><button type="button" aria-expanded={open} aria-controls="route-snapshot" onClick={()=>setOpen(!open)} className="mt-5 min-h-11 rounded-xl border border-[#111] px-4 text-sm font-bold text-[#111] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-4">View checkpoint</button><motion.div id="route-snapshot" initial={false} animate={{height:open?72:0,opacity:open?1:0,y:open?0:-4}} transition={{duration:reduced ? .12 : .22}} className="overflow-hidden"><p className="mt-3 rounded-2xl bg-[#f4f5f6] p-3 text-sm text-[#4a4a4f]"><b className="text-[#111]">Review:</b> owner sign-off at 14:30.</p></motion.div></article>}
